@code {
    // ── Navigation ──
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";

    // ── Common state ──
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;
    private bool _toastIsError;

    // ── Profile ──
    private UserProfile? _savedProfile;
    private string _editDisplayName = "";
    private string _editEmail = "";
    private string _editAvatarUrl = "";
    private string _editBio = "";

    // ── Notifications ──
    private bool _editEmailNotifications;
    private bool _editPushNotifications;
    private bool _editWeeklyDigest;
    private List<string> _allChannels = [];
    private List<bool> _mutedFlags = [];

    // ── Security ──
    private SecuritySettings? _security;
    private bool _editTwoFactorEnabled;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private ActiveSession? _sessionToRevoke;
    private const string _currentSessionId = "sess-1";

    // ── Appearance ──
    private string _editTheme = "Light";
    private string _editFontSize = "Medium";
    private string _editLanguage = "English";
    private bool _editCompactMode;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettings();
        _loading = false;
    }

    private async Task LoadAllSettings()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var secTask = SettingsService.GetSecuritySettingsAsync();
        var appearTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, secTask, appearTask);

        // Profile
        _savedProfile = profileTask.Result;
        ApplyProfile(_savedProfile);

        // Notifications
        var notifPrefs = notifTask.Result;
        _editEmailNotifications = notifPrefs.EmailNotifications;
        _editPushNotifications = notifPrefs.PushNotifications;
        _editWeeklyDigest = notifPrefs.WeeklyDigest;
        _allChannels = new List<string>(notifPrefs.MutedChannels);
        _mutedFlags = _allChannels.Select(_ => true).ToList();

        // Security
        _security = secTask.Result;
        _editTwoFactorEnabled = _security.TwoFactorEnabled;

        // Appearance
        var appearance = appearTask.Result;
        _editTheme = appearance.Theme;
        _editFontSize = appearance.FontSize;
        _editLanguage = appearance.Language;
        _editCompactMode = appearance.CompactMode;
    }

    private void SetActiveSection(string section)
    {
        _activeSection = section;
        DismissToast();
    }

    // ── Profile helpers ──

    private void ApplyProfile(UserProfile profile)
    {
        _editDisplayName = profile.DisplayName;
        _editEmail = profile.Email;
        _editAvatarUrl = profile.AvatarUrl;
        _editBio = profile.Bio;
    }

    private async Task SaveProfile()
    {
        _saving = true;
        var updated = new UserProfile(_editDisplayName, _editEmail, _editAvatarUrl, _editBio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        _saving = false;
        ShowToast("Profile saved successfully.");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        ShowToast("Changes discarded.");
    }

    // ── Notifications helpers ──

    private void ToggleMute(int index, bool muted)
    {
        _mutedFlags[index] = muted;
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        var mutedChannels = _allChannels
            .Where((ch, i) => _mutedFlags[i])
            .ToList();
        var prefs = new NotificationPrefs(_editEmailNotifications, _editPushNotifications, _editWeeklyDigest, mutedChannels);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        ShowToast("Notification preferences saved.");
    }

    // ── Security helpers ──

    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowToast("Please fill in all password fields.", isError: true);
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            ShowToast("New passwords do not match.", isError: true);
            return;
        }

        _saving = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _passwordPanelOpen = false;
        _saving = false;
        ShowToast("Password updated successfully.");
    }

    private void PromptRevokeSession(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        _saving = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _sessionToRevoke = null;
        _saving = false;
        ShowToast("Session revoked.");
    }

    // ── Appearance helpers ──

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        if (_editTheme == "Dark") classes.Add("preview-dark");
        if (_editFontSize == "Small") classes.Add("preview-font-sm");
        else if (_editFontSize == "Large") classes.Add("preview-font-lg");
        if (_editCompactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        var settings = new AppearanceSettings(_editTheme, _editFontSize, _editLanguage, _editCompactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _saving = false;
        ShowToast("Appearance settings saved.");
    }

    // ── Toast ──

    private void ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
    }

    private void DismissToast() => _toastMessage = null;

    // ── Formatting ──

    private static string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🛡",
        "Appearance" => "🎨",
        _ => "•"
    };

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

/* ── Settings layout ── */

.settings-layout {
    display: flex;
    gap: 2rem;
    min-height: 500px;
}

/* ── Sidebar ── */

.settings-sidebar {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
    min-width: 200px;
    border-right: 1px solid #dee2e6;
    padding-right: 1rem;
}

.settings-nav-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.6rem 1rem;
    border: none;
    background: none;
    border-radius: 0.375rem;
    font-size: 0.95rem;
    color: #495057;
    cursor: pointer;
    text-align: left;
    transition: background-color 0.15s, color 0.15s;
}

    .settings-nav-item:hover {
        background-color: #f0f0f0;
    }

    .settings-nav-item.active {
        background-color: #0d6efd;
        color: #fff;
        font-weight: 600;
    }

