    font-size: 1.15rem;
}

/* ── Content ── */

.settings-content {
    flex: 1;
    min-width: 0;
}

.settings-section-title {
    margin-bottom: 0.25rem;
}

/* ── Avatar ── */

.avatar-preview-area {
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 0.5rem;
}

.avatar-frame {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid #dee2e6;
}

.avatar-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

/* ── Appearance Preview ── */

.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    display: grid;
    grid-template-columns: 60px 1fr;
    grid-template-rows: 40px 1fr;
    min-height: 200px;
    font-size: 0.9rem;
    transition: all 0.2s;
    background: #fff;
    color: #212529;
}

.preview-header {
    grid-column: 1 / -1;
    background: #e9ecef;
    display: flex;
    align-items: center;
    padding: 0 1rem;
    border-bottom: 1px solid #dee2e6;
}

.preview-sidebar {
