    align-items: center;
    justify-content: center;
    border-right: 1px solid #dee2e6;
    font-size: 0.75rem;
    color: #6c757d;
}

.preview-body {
    padding: 1rem;
}

/* Dark theme preview */
.preview-dark {
    background: #1e1e1e;
    color: #e0e0e0;
    border-color: #444;
}

    .preview-dark .preview-header {
        background: #2d2d2d;
        border-color: #444;
    }

    .preview-dark .preview-sidebar {
        background: #252525;
        border-color: #444;
        color: #aaa;
    }

/* Font size variants */
.preview-font-sm {
    font-size: 0.78rem;
}

.preview-font-lg {
    font-size: 1.1rem;
}

/* Compact mode */
.preview-compact .preview-header {
    height: 30px;
    min-height: 30px;
}

.preview-compact .preview-body {
    padding: 0.5rem;
}

.preview-compact .preview-sidebar {
    width: 40px;
}

.preview-compact {
    grid-template-columns: 40px 1fr;
    grid-template-rows: 30px 1fr;
    min-height: 150px;
}

/* ── Responsive ── */

@@media (max-width: 768px) {
    .settings-layout {
        flex-direction: column;
    }

    .settings-sidebar {
        flex-direction: row;
        overflow-x: auto;
        border-right: none;
        border-bottom: 1px solid #dee2e6;
        padding-right: 0;
        padding-bottom: 0.5rem;
