@page "/settings"
@using sv_03f5d5578d9545b6b0387a8f30c10c1d.Models
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<h3 class="mb-4">⚙ Settings</h3>

@if (_loading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else
{
    <div class="settings-layout">
        <!-- Left sidebar navigation -->
        <nav class="settings-sidebar">
            @foreach (var section in _sections)
            {
                <button class="settings-nav-item @(section == _activeSection ? "active" : "")"
                        @onclick="() => SetActiveSection(section)">
                    <span class="settings-nav-icon">@GetSectionIcon(section)</span>
                    @section
                </button>
            }
        </nav>

        <!-- Main content area -->
        <div class="settings-content">
            @if (!string.IsNullOrEmpty(_toastMessage))
            {
                <div class="alert @(_toastIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @_toastMessage
                    <button type="button" class="btn-close" @onclick="DismissToast"></button>
                </div>
            }

            @switch (_activeSection)
            {
                case "Profile":
                    @RenderProfileSection()
                    break;
                case "Notifications":
                    @RenderNotificationsSection()
                    break;
                case "Security":
                    @RenderSecuritySection()
                    break;
                case "Appearance":
                    @RenderAppearanceSection()
                    break;
            }
        </div>
    </div>
}

