                    <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_editPushNotifications" />
                    <label class="form-check-label" for="pushNotif">Push Notifications</label>
                </div>
                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_editWeeklyDigest" />
                    <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
                </div>
            </div>

            <h5>Muted Channels</h5>
            <p class="text-muted small">Uncheck a channel to unmute it.</p>
            <div class="list-group mb-4">
                @for (var i = 0; i < _allChannels.Count; i++)
                {
                    var index = i;
                    var channel = _allChannels[index];
                    <label class="list-group-item d-flex align-items-center">
                        <input class="form-check-input me-2" type="checkbox"
                               checked="@_mutedFlags[index]"
                               @onchange="e => ToggleMute(index, (bool)(e.Value ?? false))" />
                        <span class="me-2">🔇</span> #@channel
                    </label>
                }
            </div>

            <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save Preferences
            </button>
        </div>;
}

@* ───── Security ───── *@

@{
    RenderFragment RenderSecuritySection() =>
        @<div>
            <h4 class="settings-section-title">Security</h4>
            <p class="text-muted">Manage your security settings and sessions.</p>

            <!-- Change Password expandable panel -->
            <div class="card mb-4">
                <div class="card-header d-flex justify-content-between align-items-center"
                     style="cursor:pointer" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <strong>🔑 Change Password</strong>
                    <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
                </div>
                @if (_passwordPanelOpen)
                {
                    <div class="card-body">
                        <div class="mb-3">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Confirm New Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-warning" @onclick="ChangePassword" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Update Password
                        </button>
                    </div>
                }
            </div>

            <!-- Two-Factor Authentication -->
            <div class="card mb-4">
                <div class="card-body d-flex justify-content-between align-items-center">
                    <div>
                        <strong>Two-Factor Authentication</strong>
                        <div class="mt-1">
                            @if (_editTwoFactorEnabled)
                            {
                                <span class="badge bg-success">Enabled</span>
                            }
                            else
                            {
                                <span class="badge bg-secondary">Disabled</span>
                            }
                        </div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" @bind="_editTwoFactorEnabled" />
                    </div>
                </div>
            </div>

            @if (_security?.LastPasswordChange is not null)
            {
                <p class="text-muted small mb-4">Last password change: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
            }

            <!-- Active Sessions -->
            <h5 class="mb-3">Active Sessions</h5>
            <div class="table-responsive">
                <table class="table table-hover align-middle">
                    <thead class="table-light">
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @if (_security?.Sessions is not null)
                        {
                            @foreach (var session in _security.Sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (session.Id != _currentSessionId)
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => PromptRevokeSession(session)">
                                                Revoke
                                            </button>
                                        }
                                        else
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        }
                    </tbody>
                </table>
            </div>

            <!-- Revoke confirmation dialog -->
            @if (_sessionToRevoke is not null)
            {
                <div class="modal-backdrop show"></div>
                <div class="modal d-block" tabindex="-1">
                    <div class="modal-dialog modal-dialog-centered">
                        <div class="modal-content">
                            <div class="modal-header">
                                <h5 class="modal-title">Revoke Session</h5>
                                <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                            </div>
                            <div class="modal-body">
                                <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                            </div>
                            <div class="modal-footer">
                                <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                                <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_saving">
                                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                                    Revoke
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            }
        </div>;
}

@* ───── Appearance ───── *@

@{
    RenderFragment RenderAppearanceSection() =>
        @<div>
            <h4 class="settings-section-title">Appearance</h4>
            <p class="text-muted">Customize the look and feel of the app.</p>

            <div class="row g-4">
                <div class="col-md-6">
                    <!-- Theme -->
