                    var channel = _allChannels[index];
                    <label class="list-group-item d-flex align-items-center">
                        <input class="form-check-input me-2" type="checkbox"
                               checked="@_mutedFlags[index]"
                               @onchange="e => ToggleMute(index, (bool)(e.Value ?? false))" />
                        <span class="me-2">🔇</span> #@channel
                    </label>
                }
            </div>

            <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save Preferences
            </button>
        </div>;
}

@* ───── Security ───── *@

@{
    RenderFragment RenderSecuritySection() =>
        @<div>
            <h4 class="settings-section-title">Security</h4>
            <p class="text-muted">Manage your security settings and sessions.</p>

            <!-- Change Password expandable panel -->
            <div class="card mb-4">
                <div class="card-header d-flex justify-content-between align-items-center"
                     style="cursor:pointer" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                    <strong>🔑 Change Password</strong>
                    <span>@(_passwordPanelOpen ? "▲" : "▼")</span>
                </div>
                @if (_passwordPanelOpen)
                {
                    <div class="card-body">
                        <div class="mb-3">
                            <label class="form-label">Current Password</label>
                            <input type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">New Password</label>
                            <input type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label">Confirm New Password</label>
                            <input type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        <button class="btn btn-warning" @onclick="ChangePassword" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Update Password
                        </button>
                    </div>
                }
            </div>

            <!-- Two-Factor Authentication -->
            <div class="card mb-4">
                <div class="card-body d-flex justify-content-between align-items-center">
                    <div>
                        <strong>Two-Factor Authentication</strong>
                        <div class="mt-1">
                            @if (_editTwoFactorEnabled)
                            {
                                <span class="badge bg-success">Enabled</span>
                            }
                            else
                            {
                                <span class="badge bg-secondary">Disabled</span>
                            }
                        </div>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" @bind="_editTwoFactorEnabled" />
                    </div>
                </div>
            </div>

            @if (_security?.LastPasswordChange is not null)
            {
                <p class="text-muted small mb-4">Last password change: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
            }

            <!-- Active Sessions -->
            <h5 class="mb-3">Active Sessions</h5>
            <div class="table-responsive">
                <table class="table table-hover align-middle">
                    <thead class="table-light">
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @if (_security?.Sessions is not null)
                        {
                            @foreach (var session in _security.Sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (session.Id != _currentSessionId)
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => PromptRevokeSession(session)">
                                                Revoke
                                            </button>
                                        }
                                        else
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        }
                    </tbody>
                </table>
            </div>

            <!-- Revoke confirmation dialog -->
            @if (_sessionToRevoke is not null)
            {
                <div class="modal-backdrop show"></div>
                <div class="modal d-block" tabindex="-1">
                    <div class="modal-dialog modal-dialog-centered">
                        <div class="modal-content">
                            <div class="modal-header">
                                <h5 class="modal-title">Revoke Session</h5>
                                <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                            </div>
                            <div class="modal-body">
                                <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                            </div>
                            <div class="modal-footer">
                                <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                                <button class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_saving">
                                    @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                                    Revoke
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            }
        </div>;
}

@* ───── Appearance ───── *@

@{
    RenderFragment RenderAppearanceSection() =>
        @<div>
            <h4 class="settings-section-title">Appearance</h4>
            <p class="text-muted">Customize the look and feel of the app.</p>

            <div class="row g-4">
                <div class="col-md-6">
                    <!-- Theme -->
                    <div class="mb-4">
                        <label class="form-label fw-semibold">Theme</label>
                        @foreach (var theme in new[] { "Light", "Dark", "System" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="theme-@theme" value="@theme"
                                       checked="@(_editTheme == theme)"
                                       @onchange="() => _editTheme = theme" />
                                <label class="form-check-label" for="theme-@theme">@theme</label>
                            </div>
                        }
                    </div>

                    <!-- Font Size -->
                    <div class="mb-4">
                        <label class="form-label fw-semibold">Font Size</label>
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="fs-@size" value="@size"
                                       checked="@(_editFontSize == size)"
                                       @onchange="() => _editFontSize = size" />
                                <label class="form-check-label" for="fs-@size">@size</label>
                            </div>
                        }
                    </div>

                    <!-- Language -->
                    <div class="mb-4">
                        <label class="form-label fw-semibold">Language</label>
                        <select class="form-select" @bind="_editLanguage">
                            <option value="English">English</option>
                            <option value="Spanish">Spanish</option>
                            <option value="French">French</option>
                            <option value="German">German</option>
                            <option value="Japanese">Japanese</option>
                            <option value="Chinese">Chinese</option>
                        </select>
                    </div>

                    <!-- Compact Mode -->
                    <div class="mb-4">
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" id="compactMode" @bind="_editCompactMode" />
                            <label class="form-check-label" for="compactMode">Compact Mode</label>
                        </div>
                    </div>
                </div>

                <!-- Live Preview -->
                <div class="col-md-6">
                    <label class="form-label fw-semibold">Live Preview</label>
                    <div class="appearance-preview @GetPreviewClasses()">
                        <div class="preview-header">
                            <strong>Preview</strong>
                        </div>
                        <div class="preview-body">
                            <p>This is how your content will look with the selected settings.</p>
                            <button class="btn btn-sm @(_editTheme == "Dark" ? "btn-light" : "btn-primary")">Sample Button</button>
                        </div>
                        <div class="preview-sidebar">Nav</div>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary mt-3" @onclick="SaveAppearance" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save
            </button>
        </div>;
}

@code {
    // ── Navigation ──
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";

    // ── Common state ──
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;
    private bool _toastIsError;

    // ── Profile ──
    private UserProfile? _savedProfile;
    private string _editDisplayName = "";
    private string _editEmail = "";
    private string _editAvatarUrl = "";
    private string _editBio = "";

    // ── Notifications ──
    private bool _editEmailNotifications;
    private bool _editPushNotifications;
    private bool _editWeeklyDigest;
    private List<string> _allChannels = [];
    private List<bool> _mutedFlags = [];

    // ── Security ──
    private SecuritySettings? _security;
    private bool _editTwoFactorEnabled;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private ActiveSession? _sessionToRevoke;
    private const string _currentSessionId = "sess-1";

    // ── Appearance ──
    private string _editTheme = "Light";
    private string _editFontSize = "Medium";
    private string _editLanguage = "English";
    private bool _editCompactMode;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettings();
        _loading = false;
    }

    private async Task LoadAllSettings()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var secTask = SettingsService.GetSecuritySettingsAsync();
        var appearTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, secTask, appearTask);

        // Profile
        _savedProfile = profileTask.Result;
        ApplyProfile(_savedProfile);

        // Notifications
        var notifPrefs = notifTask.Result;
        _editEmailNotifications = notifPrefs.EmailNotifications;
        _editPushNotifications = notifPrefs.PushNotifications;
        _editWeeklyDigest = notifPrefs.WeeklyDigest;
        _allChannels = new List<string>(notifPrefs.MutedChannels);
        _mutedFlags = _allChannels.Select(_ => true).ToList();

        // Security
        _security = secTask.Result;
        _editTwoFactorEnabled = _security.TwoFactorEnabled;

        // Appearance
        var appearance = appearTask.Result;
        _editTheme = appearance.Theme;
        _editFontSize = appearance.FontSize;
        _editLanguage = appearance.Language;
        _editCompactMode = appearance.CompactMode;
    }

    private void SetActiveSection(string section)
    {
        _activeSection = section;
        DismissToast();
    }

    // ── Profile helpers ──

    private void ApplyProfile(UserProfile profile)
    {
        _editDisplayName = profile.DisplayName;
        _editEmail = profile.Email;
        _editAvatarUrl = profile.AvatarUrl;
        _editBio = profile.Bio;
    }

    private async Task SaveProfile()
    {
        _saving = true;
        var updated = new UserProfile(_editDisplayName, _editEmail, _editAvatarUrl, _editBio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        _saving = false;
        ShowToast("Profile saved successfully.");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
        ShowToast("Changes discarded.");
    }

    // ── Notifications helpers ──

    private void ToggleMute(int index, bool muted)
    {
        _mutedFlags[index] = muted;
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        var mutedChannels = _allChannels
            .Where((ch, i) => _mutedFlags[i])
            .ToList();
        var prefs = new NotificationPrefs(_editEmailNotifications, _editPushNotifications, _editWeeklyDigest, mutedChannels);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        ShowToast("Notification preferences saved.");
    }

    // ── Security helpers ──

    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowToast("Please fill in all password fields.", isError: true);
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            ShowToast("New passwords do not match.", isError: true);
            return;
        }

        _saving = true;
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _passwordPanelOpen = false;
        _saving = false;
        ShowToast("Password updated successfully.");
    }

    private void PromptRevokeSession(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        _saving = true;
        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _security = await SettingsService.GetSecuritySettingsAsync();
        _sessionToRevoke = null;
        _saving = false;
        ShowToast("Session revoked.");
    }

    // ── Appearance helpers ──

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        if (_editTheme == "Dark") classes.Add("preview-dark");
        if (_editFontSize == "Small") classes.Add("preview-font-sm");
        else if (_editFontSize == "Large") classes.Add("preview-font-lg");
        if (_editCompactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        var settings = new AppearanceSettings(_editTheme, _editFontSize, _editLanguage, _editCompactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _saving = false;
        ShowToast("Appearance settings saved.");
    }

    // ── Toast ──

    private void ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
    }

    private void DismissToast() => _toastMessage = null;

    // ── Formatting ──

    private static string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🛡",
        "Appearance" => "🎨",
        _ => "•"
    };

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

/* ── Settings layout ── */

.settings-layout {
    display: flex;
    gap: 2rem;
    min-height: 500px;
}

/* ── Sidebar ── */

.settings-sidebar {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
    min-width: 200px;
    border-right: 1px solid #dee2e6;
    padding-right: 1rem;
}

.settings-nav-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.6rem 1rem;
    border: none;
    background: none;
    border-radius: 0.375rem;
    font-size: 0.95rem;
    color: #495057;
    cursor: pointer;
    text-align: left;
    transition: background-color 0.15s, color 0.15s;
}

    .settings-nav-item:hover {
        background-color: #f0f0f0;
    }

    .settings-nav-item.active {
        background-color: #0d6efd;
        color: #fff;
        font-weight: 600;
    }

.settings-nav-icon {
    font-size: 1.15rem;
}

/* ── Content ── */

.settings-content {
    flex: 1;
    min-width: 0;
}

.settings-section-title {
    margin-bottom: 0.25rem;
}

/* ── Avatar ── */

.avatar-preview-area {
    padding: 1rem;
    background: #f8f9fa;
    border-radius: 0.5rem;
}

.avatar-frame {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid #dee2e6;
}

.avatar-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

/* ── Appearance Preview ── */

.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    display: grid;
    grid-template-columns: 60px 1fr;
    grid-template-rows: 40px 1fr;
    min-height: 200px;
    font-size: 0.9rem;
    transition: all 0.2s;
    background: #fff;
    color: #212529;
}

.preview-header {
    grid-column: 1 / -1;
    background: #e9ecef;
    display: flex;
    align-items: center;
    padding: 0 1rem;
    border-bottom: 1px solid #dee2e6;
}

.preview-sidebar {
    background: #f8f9fa;
    display: flex;
    align-items: center;
    justify-content: center;
    border-right: 1px solid #dee2e6;
    font-size: 0.75rem;
    color: #6c757d;
}

.preview-body {
    padding: 1rem;
}

/* Dark theme preview */
.preview-dark {
    background: #1e1e1e;
    color: #e0e0e0;
    border-color: #444;
}

    .preview-dark .preview-header {
        background: #2d2d2d;
        border-color: #444;
    }

    .preview-dark .preview-sidebar {
        background: #252525;
        border-color: #444;
        color: #aaa;
    }

/* Font size variants */
.preview-font-sm {
    font-size: 0.78rem;
}

.preview-font-lg {
    font-size: 1.1rem;
}

/* Compact mode */
.preview-compact .preview-header {
    height: 30px;
    min-height: 30px;
}

.preview-compact .preview-body {
    padding: 0.5rem;
}

.preview-compact .preview-sidebar {
    width: 40px;
}

.preview-compact {
    grid-template-columns: 40px 1fr;
    grid-template-rows: 30px 1fr;
    min-height: 150px;
}

/* ── Responsive ── */

@@media (max-width: 768px) {
    .settings-layout {
        flex-direction: column;
    }

    .settings-sidebar {
        flex-direction: row;
        overflow-x: auto;
        border-right: none;
        border-bottom: 1px solid #dee2e6;
        padding-right: 0;
        padding-bottom: 0.5rem;
        min-width: unset;
    }

    .settings-nav-item {
        white-space: nowrap;
    }
}

