+/* ── Settings layout ── */
+
+.settings-layout {
+    display: flex;
+    gap: 2rem;
+    min-height: 500px;
+}
+
+/* ── Sidebar ── */
+
+.settings-sidebar {
+    display: flex;
+    flex-direction: column;
+    gap: 0.25rem;
+    min-width: 200px;
+    border-right: 1px solid #dee2e6;
+    padding-right: 1rem;
+}
+
+.settings-nav-item {
+    display: flex;
+    align-items: center;
+    gap: 0.6rem;
+    padding: 0.6rem 1rem;
+    border: none;
+    background: none;
+    border-radius: 0.375rem;
+    font-size: 0.95rem;
+    color: #495057;
+    cursor: pointer;
+    text-align: left;
+    transition: background-color 0.15s, color 0.15s;
+}
+
+    .settings-nav-item:hover {
+        background-color: #f0f0f0;
+    }
+
+    .settings-nav-item.active {
+        background-color: #0d6efd;
+        color: #fff;
+        font-weight: 600;
+    }
+
+.settings-nav-icon {
+    font-size: 1.15rem;
+}
+
+/* ── Content ── */
+
+.settings-content {
+    flex: 1;
+    min-width: 0;
+}
+
+.settings-section-title {
+    margin-bottom: 0.25rem;
+}
+
+/* ── Avatar ── */
+
+.avatar-preview-area {
+    padding: 1rem;
+    background: #f8f9fa;
+    border-radius: 0.5rem;
+}
+
+.avatar-frame {
+    width: 120px;
+    height: 120px;
+    border-radius: 50%;
+    overflow: hidden;
+    border: 3px solid #dee2e6;
+}
+
+.avatar-img {
+    width: 100%;
+    height: 100%;
+    object-fit: cover;
+}
+
+/* ── Appearance Preview ── */
+
+.appearance-preview {
+    border: 1px solid #dee2e6;
+    border-radius: 0.5rem;
+    overflow: hidden;
+    display: grid;
+    grid-template-columns: 60px 1fr;
+    grid-template-rows: 40px 1fr;
+    min-height: 200px;
+    font-size: 0.9rem;
+    transition: all 0.2s;
+    background: #fff;
+    color: #212529;
+}
+
+.preview-header {
+    grid-column: 1 / -1;
+    background: #e9ecef;
+    display: flex;
+    align-items: center;
+    padding: 0 1rem;
+    border-bottom: 1px solid #dee2e6;
+}
+
+.preview-sidebar {
+    background: #f8f9fa;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    border-right: 1px solid #dee2e6;
+    font-size: 0.75rem;
+    color: #6c757d;
+}
+
+.preview-body {
+    padding: 1rem;
+}
+
+/* Dark theme preview */
+.preview-dark {
+    background: #1e1e1e;
+    color: #e0e0e0;
+    border-color: #444;
+}
+
+    .preview-dark .preview-header {
+        background: #2d2d2d;
+        border-color: #444;
+    }
+
+    .preview-dark .preview-sidebar {
+        background: #252525;
+        border-color: #444;
+        color: #aaa;
+    }
+
+/* Font size variants */
+.preview-font-sm {
+    font-size: 0.78rem;
+}
+
+.preview-font-lg {
+    font-size: 1.1rem;
+}
+
+/* Compact mode */
+.preview-compact .preview-header {
+    height: 30px;
+    min-height: 30px;
+}
+
+.preview-compact .preview-body {
+    padding: 0.5rem;
+}
+
+.preview-compact .preview-sidebar {
+    width: 40px;
+}
+
+.preview-compact {
+    grid-template-columns: 40px 1fr;
+    grid-template-rows: 30px 1fr;
+    min-height: 150px;
+}
+
+/* ── Responsive ── */
+
+@@media (max-width: 768px) {
+    .settings-layout {
+        flex-direction: column;
+    }
+
+    .settings-sidebar {
+        flex-direction: row;
+        overflow-x: auto;
+        border-right: none;
+        border-bottom: 1px solid #dee2e6;
+        padding-right: 0;
+        padding-bottom: 0.5rem;
+        min-width: unset;
+    }
+
+    .settings-nav-item {
+        white-space: nowrap;
+    }
+}
+

